      before_start:
        '{"blocks":[{"key":"dqes6","text":"Ensure you have an appropriate E. coli cloning/donor strain that contains the RP4 conjugative machinery to enable conjugal transfer of pIV101. Some commonly used strains for this include: E. coli S17/ST18, E. coli MFDpir, E. coli WM3064. ","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"italic","offset":31,"length":8},{"style":"italic","offset":188,"length":8},{"style":"italic","offset":206,"length":8},{"style":"italic","offset":217,"length":13}],"entityRanges":[],"data":{}},{"key":"ehosb","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"bf0dc","text":"If using an auxotrophic E. coli strain such as ST18 or MFDpir make sure you have the required supplement (e.g. 5-aminolevulinic acid (ALA) for ST18 or diaminopimelic acid (DAP) for MFDpir).","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"italic","offset":24,"length":8},{"style":"italic","offset":58,"length":4},{"style":"italic","offset":184,"length":3}],"entityRanges":[],"data":{}},{"key":"7ltvc","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"8a04q","text":"pIV101 is available on Addgene and can be found here: https://www.addgene.org/196671/.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":0,"offset":54,"length":31}],"data":{}},{"key":"fvtj3","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"almlq","text":"You must have a pBR322-derived R. rhizogenes acceptor strain e.g. R. rhizogenes AR1193.","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"italic","offset":31,"length":13},{"style":"italic","offset":66,"length":14}],"entityRanges":[],"data":{}}],"entityMap":{"0":{"type":"link","mutability":"MUTABLE","data":{"guid":"36D76C69B86711EDBAC80A58A9FEAC02","url":"https://www.addgene.org/196671"}}}}',
      created_on: 1674637901,
