      before_start:
        '{"blocks":[{"key":"6rdgv","text":"Collect the biological samples ","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"bold","offset":0,"length":31}],"entityRanges":[],"data":{}},{"key":"fmm4e","text":"Adult Amphimedon queenslandica sponges were collected from the intertidal reef flat of Shark Bay, Heron Island Reef, and transferred to outdoor aquaria at Heron Island Research Station with flow-through, unfiltered ambient seawater drawn from the adjacent reef flat (Leys et al., 2008). The coralline alga Amphiroa fragilissima was collected from the reef flat on the southern side of the reef and used as the settlement substratum for Amphimedon larvae (Degnan \\u0026 Degnan, 2010; Say \\u0026 Degnan, 2020). Naturally emerging larvae were collected in the early to mid-afternoon using plastic disposable transfer pipettes, and maintained in ambient conditions before transferring to 6-well plates with 10 mL of 0.22 µm filtered seawater (FSW) (10 larvae per well) for settlement on A. fragilissima at sunset (Leys et al., 2008; Say \\u0026 Degnan, 2020). Individuals of still-swimming larvae and settled postlarvae were collected at precise timepoints designated by the experimental design and immediately dissociated as described below. ","type":"align-justify","depth":0,"inlineStyleRanges":[{"style":"italic","offset":6,"length":24},{"style":"italic","offset":306,"length":21},{"style":"italic","offset":436,"length":10},{"style":"italic","offset":773,"length":16},{"style":"italic","offset":798,"length":1}],"entityRanges":[],"data":{}}],"entityMap":{}}',
