        '{"blocks":[{"key":"9r2d1","text":"Materials ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"3i5d5","text":"Pure DNA","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"7720m","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"s4o7","text":"Consumables ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"5in2o","text":"R10.4.1 MinION flowcell Flow Cell (R10.4.1) (nanoporetech.com)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":0,"offset":24,"length":38}],"data":{}},{"key":"cfs8n","text":"SQK-LSK114 Ligation Sequencing Kit V14 (nanoporetech.com)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":1,"offset":11,"length":46}],"data":{}},{"key":"dr2id","text":"Primers as described.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"4trei","text":"Q5 High-Fidelity Polymerase","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"7s08b","text":"NEBNext Ultra II End repair/dA-tailing Module (NEB, E7546)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"chn3i","text":"NEBNext Quick Ligation Module (NEB, E6056)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"59h1o","text":"Bovine Serum Albumin (BSA) (50 mg/ml) (e.g Invitrogen‱ UltraPure‱ BSA 50 mg/ml, AM2616)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":2,"offset":53,"length":1},{"key":3,"offset":64,"length":1}],"data":{}},{"key":"46gdj","text":"magnetic beads (AMPure or equivalent) https://www.beckman.com/reagents/genomic/cleanup-and-size-selection/pcr","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":4,"offset":38,"length":71}],"data":{}},{"key":"etv2t","text":"1.5 ml Eppendorf DNA LoBind tubes ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"bdscl","text":"0.2 ml thin-walled PCR tubes ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"9ube3","text":"Nuclease-free water (e.g. ThermoFisher)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"bc5kc","text":"Freshly prepared 80% ethanol in nuclease-free water ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"eh8f3","text":"Qubit Assay Tubes (ThermoFisher) ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"e04js","text":"Qubit dsDNA BR Assay Kit (ThermoFisher)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"dlvs7","text":"\\n","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"ftudu","text":"Equipment ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"515f3","text":"Hula mixer (gentle rotator mixer) ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"6m6g8","text":"Microfuge Magnetic rack ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"b2jpj","text":"Vortex mixer ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"7fpjl","text":"Thermal cycler/PCR machine","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"fuq60","text":"Multichannel pipette ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"anpl9","text":"P1000 pipette and tips","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"d7f46","text":"P200 pipette and tips ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"8hhk3","text":"P100 pipette and tips","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"66rm1","text":"P20 pipette and tips ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"84kcd","text":"P10 pipette and tips ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"35j66","text":"P2 pipette and tips ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"454oj","text":"Ice bucket with ice Timer","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"c83aq","text":"Qubit fluorometer (or equivalent for QC check) ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"es3tp","text":"Computer with the latest version of MinKNOW installed.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"4rj44","text":"MinION Nanopore sequencer","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"9qabn","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}}],"entityMap":{"0":{"type":"link","mutability":"MUTABLE","data":{"guid":"2D9C8B37DDE411EE9F470A58A9FEAC02","url":"https://store.nanoporetech.com/flow-cell-r10-4-1.html"}},"1":{"type":"link","mutability":"MUTABLE","data":{"guid":"1DBBE2D3DE7E11EEA7150A58A9FEAC02","url":"https://store.nanoporetech.com/ligation-sequencing-kit-v14.html"}},"2":{"type":"emoji","mutability":"MUTABLE","data":{"guid":"5BFE9CFBDE7E11EEA7150A58A9FEAC02","name":":tm:"}},"3":{"type":"emoji","mutability":"MUTABLE","data":{"guid":"5BFE9CFBDE7E11EEA7150A58A9FEAC02","name":":tm:"}},"4":{"type":"link","mutability":"MUTABLE","data":{"guid":"814F475DDDE311EE9F470A58A9FEAC02","url":"https://www.beckman.com/reagents/genomic/cleanup-and-size-selection/pcr"}}}}',
