      guidelines:
        '{"blocks":[{"key":"b4prl","text":"You must have read, understood, and follow the health and safety instructions provided in the \\"Overview Mini-Research Project #1 BIOL3106/6106\\" provided on Wattle (ANU learning portal). ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"1nthn","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"18q4p","text":"You must have signed and returned one copy of the \\"Student Safety Declaration Form For Practical Class Work\\" before starting any laboratory work. ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"drk11","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"jqoe","text":"You must have read and understood the Hazard Sheets (Risk assessment) of all chemicals listed bellow in the \\"Safety Warnings\\" section. These Hazard Sheets are provided on Wattle as part of the  \\"Overview Mini-Research Project #1 BIOL3106/6106\\" document.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}}],"entityMap":{}}',
      id: 119846,
