      materials: [],
      materials_text:
        '{"blocks":[{"key":"84uv3","text":"As always you need to bring a lab notebook, a printed version of this protocol, and a pen to record your adventures in the lab.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"7nb8l","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"e9mq6","text":"Consumables and culture material needed:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"e98fq","text":"Pre-cast 1% Agarose Gel in TBE","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"2nu95","text":"PCR strip tubes","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"9uo71","text":"Gel Loading Dye, Purple (6X); 20 uL total. https://www.nebiolabs.com.au/products/b7024-gel-loading-dye-purple-6x#Product%20Information","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":0,"offset":43,"length":91}],"data":{}},{"key":"7vjhc","text":"DNA ladder; 12 uL total. https://www.nebiolabs.com.au/products/n0550-quick-load-purple-1-kb-plus-dna-ladder#Product%20Information","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":1,"offset":25,"length":104}],"data":{}},{"key":"5n38k","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"a2fg","text":"Equipment needed:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"22avm","text":"Mini benchtop spinner for PCR strip tubes of 8.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"49pf9","text":"Voltage block.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"5qfgq","text":"DNA gel electrophoresis chamber","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}}],"entityMap":{"0":{"type":"link","mutability":"MUTABLE","data":{"guid":"A75FAC76AA8D11ED96920A58A9FEAC02","url":"https://www.nebiolabs.com.au/products/b7024-gel-loading-dye-purple-6x#Product%20Information"}},"1":{"type":"link","mutability":"MUTABLE","data":{"guid":"C52BCB4BAA8D11ED96920A58A9FEAC02","url":"https://www.nebiolabs.com.au/products/n0550-quick-load-purple-1-kb-plus-dna-ladder#Product%20Information"}}}}',
