      materials_text:
        '{"blocks":[{"key":"8gl49","text":"As always you need to bring a lab notebook, a printed version of this protocol, and a pen to record your adventures in the lab.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"3m8u9","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"dk5o5","text":"Consumables and culture material needed:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"n8pq","text":"1.5 ml tubes. At least seven in total.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"34b0l","text":"strip tubes of 8. ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"99oai","text":"Primers @ 10uM. ITSFor, ITSRev; 20ul each.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"963c","text":"Primers @ 10uM. 16SFor, 16SRev; 20ul each.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"es5qb","text":"Nuclease Free water (ddH2O)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[{"style":"sub","offset":24,"length":1}],"entityRanges":[],"data":{}},{"key":"7o6mb","text":"MyTaq HS Red DNA Polymerase Master Mix including MyTaq HS Red DNA Pol; 2x38.5ul total (One for ITS and one for 16S PCR)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"4m04i","text":"Five tubes with 198ul broad range qubit.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"f3e02","text":"Ice bucket with ice.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"65onf","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"48vvq","text":"Equipment needed:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"38vqu","text":"Benchtop centrifuge for 1.5ml/2ml tubes. ","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"fmv7","text":"Mini benchtop spinner for strip tubes of 8.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"9ff9f","text":"Vortex.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"cbiq5","text":"PCR machines. Up to two PCR machines with capacity for 96 PCR reactions each.","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}}],"entityMap":{}}',
