      before_start:
        '{"blocks":[{"key":"bpc4d","text":"1. Reagents should be prepared and stored in glass labware only. We recommend using the same glass labware for every analysis to avoid external contamination by detergents or other chemicals","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"2v1ng","text":"2. We recommend preparing reagents just before starting the protocol. ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"2ohol","text":"3. Handle reagents under a fume hood only","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"2ussu","text":"4. Use ultrapure water for the preparation of reagents","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}},{"key":"9ol9i","text":"5. Wipe down all working benches with  or  prior to begin working","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[{"key":0,"offset":37,"length":1},{"key":1,"offset":42,"length":1}],"data":{}},{"key":"eba72","text":"6. All steps should be performed in a dedicated wet chemistry laboratory. If the presence of human remains is suspected, we recommend sampling in a DNA-free/P3 laboratory ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":{}}],"entityMap":{"0":{"type":"reagents","mutability":"MUTABLE","data":{"can_edit":false,"cas_number":"","guid":"41A991A3341F11EE9D4302C0B41BC903","linfor":"","mol_weight":0,"name":"70% isopropyl alcohol","pubchem_id":"0","public":1,"rrid":"","sku":"","stats":{"total_protocols":2},"url":"http://None","vendor":{"id":0,"image":{"placeholder":null,"source":"/img/vendors/1.png"},"is_requested":false,"link":"https://www.protocols.io","name":"Contributed by users"}}},"1":{"type":"reagents","mutability":"MUTABLE","data":{"can_edit":false,"cas_number":"","guid":"4106C9E6341F11EE9D4302C0B41BC903","linfor":"","mol_weight":0,"name":"70% Ethanol ","pubchem_id":"0","public":1,"rrid":"","sku":"","stats":{"total_protocols":19},"url":"","vendor":{"id":0,"image":{"placeholder":null,"source":"/img/vendors/1.png"},"is_requested":false,"link":"https://www.protocols.io","name":"Contributed by users"}}}}}',
